// Validate and insert event into Supabase
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

const body = $input.first().json.body || $input.first().json;
const { session_id, event_type, payload } = body;

// Validation
const validEventTypes = [
  'search_started', 'search_completed', 'card_viewed',
  'chip_clicked', 'source_clicked', 'feedback_given', 'session_ended'
];

if (!event_type || !validEventTypes.includes(event_type)) {
  return [{ json: { success: false, error: 'Invalid event_type' } }];
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/events`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify({
      session_id: session_id || null,
      event_type,
      payload: payload || {}
    })
  });

  const eventId = Array.isArray(response) && response.length > 0 ? response[0].id : null;
  return [{ json: { success: true, data: { event_id: eventId } } }];
} catch (error) {
  return [{ json: { success: false, error: error.message } }];
}
